"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([["649941"],{917667(i){i.exports=JSON.parse('{"tag":{"label":"behavior","permalink":"/dst-api-webdocs/docs/tags/behavior","allTagsPath":"/dst-api-webdocs/docs/tags","count":36,"items":[{"id":"game-scripts/behaviours/approach","title":"Approach","description":"A behavior node that moves an entity toward a target until it reaches a specified distance.","permalink":"/dst-api-webdocs/docs/game-scripts/behaviours/approach"},{"id":"game-scripts/behaviours/avoidelectricfence","title":"Avoidelectricfence","description":"A behavior node that forces an entity to flee away from an active electric fence when it detects proximity or shock events.","permalink":"/dst-api-webdocs/docs/game-scripts/behaviours/avoidelectricfence"},{"id":"game-scripts/components/beefalometrics","title":"Beefalometrics","description":"Records and reports metric events related to beefalo domestication, riding, attacks, and death for analytics purposes.","permalink":"/dst-api-webdocs/docs/game-scripts/components/beefalometrics"},{"id":"game-scripts/behaviourtree","title":"Behaviourtree","description":"Implements a behavior tree system for AI entity decision-making and task execution.","permalink":"/dst-api-webdocs/docs/game-scripts/behaviourtree"},{"id":"game-scripts/brains/braincommon","title":"Braincommon","description":"Provides shared utility functions and behavior tree nodes for AI brain construction.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/braincommon"},{"id":"game-scripts/brains/catcoonbrain","title":"Catcoonbrain","description":"Defines the behavior tree AI for Catcoon entities, managing following, playing, hairball throwing, and homing behaviors.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/catcoonbrain"},{"id":"game-scripts/behaviours/chattynode","title":"Chattynode","description":"A behavior node that periodically triggers speech or chatter from an entity during AI behavior execution.","permalink":"/dst-api-webdocs/docs/game-scripts/behaviours/chattynode"},{"id":"game-scripts/prefabs/clockwork_common","title":"Clockwork Common","description":"Utility module providing shared helper functions for clockwork entity behavior including sleep cycles, combat targeting, befriending, health regeneration, and trader interactions.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/clockwork_common"},{"id":"game-scripts/brains/critterbrain","title":"CritterBrain","description":"Defines AI behavior tree for critter entities including owner following, combat avoidance, playful interactions, and minigame watching.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/critterbrain"},{"id":"game-scripts/behaviours/faceentity","title":"Faceentity","description":"A behavior node that orients an entity toward a target entity, optionally triggering alert states and stopping locomotion during the facing operation.","permalink":"/dst-api-webdocs/docs/game-scripts/behaviours/faceentity"},{"id":"game-scripts/behaviours/findclosest","title":"Findclosest","description":"AI behaviour node that finds and moves toward the nearest entity matching specified tag filters.","permalink":"/dst-api-webdocs/docs/game-scripts/behaviours/findclosest"},{"id":"game-scripts/behaviours/findfarmplant","title":"Findfarmplant","description":"Selects a suitable farm plant for tending based on stress state and proximity, then initiates movement to it.","permalink":"/dst-api-webdocs/docs/game-scripts/behaviours/findfarmplant"},{"id":"game-scripts/behaviours/findflower","title":"Findflower","description":"Selects the nearest unoccupied flower within sight and plans a pollination action for the entity.","permalink":"/dst-api-webdocs/docs/game-scripts/behaviours/findflower"},{"id":"game-scripts/behaviours/findlight","title":"Findlight","description":"A behavior tree node that moves an entity toward the nearest valid light source and maintains a safe distance within it.","permalink":"/dst-api-webdocs/docs/game-scripts/behaviours/findlight"},{"id":"game-scripts/firelevel","title":"Firelevel","description":"Defines static configuration parameters for a fire-like entity\'s visual, thermal, and burning behavior.","permalink":"/dst-api-webdocs/docs/game-scripts/firelevel"},{"id":"game-scripts/brains/friendlyfruitflybrain","title":"Friendlyfruitflybrain","description":"Controls the AI behavior of friendly fruit fly entities, managing tasks like following a leader, wandering, and interacting with farm plants.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/friendlyfruitflybrain"},{"id":"game-scripts/brains/frogbrain","title":"Frogbrain","description":"Controls the decision-making logic for frog entities, managing behaviors such as wandering, sleeping, chasing targets, and returning home during night or winter.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/frogbrain"},{"id":"game-scripts/behaviours/leash","title":"Leash","description":"Controls entity movement to enforce a \\"leash\\" distance from a home point, guiding the entity toward home if it strays too far.","permalink":"/dst-api-webdocs/docs/game-scripts/behaviours/leash"},{"id":"game-scripts/components/mood","title":"Mood","description":"Manages timed and seasonal mood states for entities, such as mating behavior in beefalo, by tracking mood duration, season-based activation, and world settings multipliers.","permalink":"/dst-api-webdocs/docs/game-scripts/components/mood"},{"id":"game-scripts/brains/moosebrain","title":"Moosebrain","description":"Defines the AI behavior tree for the Moose entity, managing combat, egg-laying, and territorial behaviors.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/moosebrain"},{"id":"game-scripts/prefabs/mushgnome_spawner","title":"Mushgnome Spawner","description":"Manages the controlled spawning of Mushgnome entities in response to player proximity within a defined zone, using the ChildSpawner component.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/mushgnome_spawner"},{"id":"game-scripts/components/oceanfishable","title":"Oceanfishable","description":"Manages the fishable state and behavior of ocean creatures when interacting with fishing rods, including stamina-based struggle mechanics and movement speed adjustments based on line tension.","permalink":"/dst-api-webdocs/docs/game-scripts/components/oceanfishable"},{"id":"game-scripts/brains/oceanfishbrain","title":"Oceanfishbrain","description":"Controls the AI behavior of ocean-dwelling fish entities, including feeding, fishing hook interactions, fleeing, and wandering.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/oceanfishbrain"},{"id":"game-scripts/brains/otterbrain","title":"Otterbrain","description":"AI behavior controller for the Otter character, managing foraging, looting, fishing, and home-stashing behaviors via a priority-based behavior tree.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/otterbrain"},{"id":"game-scripts/brains/pigbrain","title":"Pigbrain","description":"AI behavior tree controlling pig NPC behaviors including following, trading, eating, combat, and event participation.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/pigbrain"},{"id":"game-scripts/components/saltlicker","title":"SaltLicker","description":"Manages entity behavior for seeking and consuming salt from saltlick objects over time.","permalink":"/dst-api-webdocs/docs/game-scripts/components/saltlicker"},{"id":"game-scripts/stategraphs/SGcharlie_heckler","title":"Sgcharlie Heckler","description":"Defines the state machine for Charlie\'s heckler entities, handling entrance, idle, exit, and interactive behaviors such as talking and giving playbills during YOTH events.","permalink":"/dst-api-webdocs/docs/game-scripts/stategraphs/SGcharlie_heckler"},{"id":"game-scripts/stategraphs/SGcozy_bunnyman","title":"Sgcozy Bunnyman","description":"Defines the animation state machine and AI behavior for the Cozy Bunnyman entity.","permalink":"/dst-api-webdocs/docs/game-scripts/stategraphs/SGcozy_bunnyman"},{"id":"game-scripts/stategraphs/SGcritter_bulbin","title":"Sgcritter Bulbin","description":"Defines the animation state machine and behavior logic for the Bulbin critter entity.","permalink":"/dst-api-webdocs/docs/game-scripts/stategraphs/SGcritter_bulbin"},{"id":"game-scripts/stategraphs/SGdeciduoustree","title":"Sgdeciduoustree","description":"Defines the state machine for deciduous tree entities, controlling animations and behavior during aggressive idle, chopping, burning, and electrocution states.","permalink":"/dst-api-webdocs/docs/game-scripts/stategraphs/SGdeciduoustree"},{"id":"game-scripts/brains/shadow_bishopbrain","title":"Shadow Bishopbrain","description":"Controls the AI behavior of the Shadow Bishop boss entity, handling movement, facing, taunting, and timed despawn logic.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/shadow_bishopbrain"},{"id":"game-scripts/components/shadowsubmissive","title":"Shadowsubmissive","description":"Grants an entity the `shadowsubmissive` tag and manages its behavioral response to shadow-dominant entities by tracking attacks and restoring the `shadowdominance` tag after a delay if conditions are met.","permalink":"/dst-api-webdocs/docs/game-scripts/components/shadowsubmissive"},{"id":"game-scripts/behaviours/standstill","title":"Standstill","description":"A behavior node that forces an entity to stop moving and remain stationary, conditionally invoking start/keep functions to determine ongoing validity.","permalink":"/dst-api-webdocs/docs/game-scripts/behaviours/standstill"},{"id":"game-scripts/prefabs/tallbirdnest","title":"Tallbirdnest","description":"Manages the tallbird nesting behavior, egg spawning, and seasonal reproduction cycle.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/tallbirdnest"},{"id":"game-scripts/brains/wobsterbrain","title":"Wobsterbrain","description":"AI controller for the Wobster entity that manages its behavior while fishing, including struggling when hooked, returning home during the day, and interacting with fishing lures.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/wobsterbrain"},{"id":"game-scripts/brains/wobycommon","title":"Wobycommon","description":"Provides shared AI behavior logic and utility functions for Woby, a companion entity in Don\'t Starve Together, including fetching, foraging, ammo retrieval, courier, and minigame watching.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/wobycommon"}],"unlisted":false}}')}}]);